#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

int cmp(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (x > y) - (x < y);
}

static inline long long comb2(long long x) {
    return x * (x - 1) / 2; // x >= 0
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, Q; scanf("%d %d", &N, &Q);
        long long *a = (long long *)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &a[i]);
        qsort(a, N, sizeof(long long), cmp);
        long long *pref = (long long *)malloc(N * sizeof(long long));
        long long cur = 0;
        for (int i = 0; i < N; ++i) {
            long long suffix = N - i - 1;
            cur += comb2(suffix);
            pref[i] = cur;
        }
        while (Q--) {
            long long K; scanf("%lld", &K);
            int lo = 0, hi = N-1, ans = N-1;
            while (lo <= hi) {
                int mid = (lo + hi) >> 1;
                if (pref[mid] >= K) { ans = mid; hi = mid - 1; }
                else lo = mid + 1;
            }
            printf("%lld\n", a[ans]);
        }
        free(a);
        free(pref);
    }
    return 0;
}

