import java.io.*;
import java.util.*;

public class Main {
    static long comb2(long x){ return x*(x-1)/2; }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            long[] a = new long[N];
            for (int i = 0; i < N; i++) a[i] = fs.nextLong();
            Arrays.sort(a);
            long[] pref = new long[N];
            long cur = 0;
            for (int i = 0; i < N; i++) {
                long suffix = N - i - 1;
                cur += comb2(suffix);
                pref[i] = cur;
            }
            for (int qi = 0; qi < Q; qi++) {
                long K = fs.nextLong();
                int idx = Arrays.binarySearch(pref, K);
                if (idx < 0) idx = -idx - 1;
                out.append(a[idx]).append('\n');
            }
        }
        System.out.print(out.toString());
    }
    // Fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false; if (c == '-') { neg = true; c = readByte(); }
            long val = 0; while (c > ' ') { val = val * 10 + (c - '0'); c = readByte(); }
            return neg ? -val : val; }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
}

